import { useEffect, useState } from "react";
import axios from "axios";
import { BarChart3, Search } from "lucide-react";
import CompanyItem from "../Compontes/CompanyItem";
import AIPrediction from "../Compontes/AIPrediction"; 
import WelcomeMessage from "../Compontes/WelcomeMessage";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { generateRandomData } from "../utils/mockStockData"

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:5050/api"; 

const StockDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [stockData, setStockData] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  // Fetch companies on page load
  useEffect(() => {
    axios.get(`${API_BASE}/companies`)
      .then(res => setCompanies(res.data))
      .catch(err => console.error("❌ Error fetching companies:", err));
  }, []);

  // Fetch stock data when company changes
  useEffect(() => {
    if (!selectedCompany) return;

    setIsLoading(true);
    axios.get(`${API_BASE}/stocks/${selectedCompany.id}`)
      .then(res => {
        const data = res.data && res.data.length ? res.data : generateRandomData(30, selectedCompany.current_price || 100, 5);
        setStockData(data);
      })
      .catch(err => {
        console.error("❌ Error fetching stock data:", err);
        // Use mock data on error
        const mock = generateRandomData(30, selectedCompany.current_price || 100, 5);
        setStockData(mock);
      })
      .finally(() => setIsLoading(false));
  }, [selectedCompany]);

  // Filter companies for search
  const filteredCompanies = companies.filter((company) =>
    (company.name || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
    (company.symbol || "").toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Chart data
  const chartData = {
    labels: stockData.labels || stockData.map(d => d.date || ""),
    datasets: [
      {
        data: stockData.data || stockData.map(d => d.close ?? 0),
        borderColor: "#3b82f6",
        backgroundColor: "rgba(59, 130, 246, 0.08)",
        borderWidth: 3,
        fill: true
      }
    ]
  };

  return (
    <div className="flex h-screen bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Sidebar */}
      <div className="w-96 bg-white shadow-2xl border-r border-gray-200">
        {/* Header */}
        <div className="p-6 bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 text-white">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center">
              <BarChart3 size={24} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold">StockVision</h1>
              <p className="text-blue-200 text-sm">JarNox Assignment</p>
            </div>
          </div>
        </div>

        {/* Search */}
        <div className="p-4 border-b border-gray-100">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
            <input
              type="text"
              placeholder="Search stocks..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-2xl"
            />
          </div>
        </div>

        {/* Company List */}
        <div className="flex-1 overflow-y-auto py-2">
          {filteredCompanies.map((company) => (
            <CompanyItem
              key={company.id}
              company={company}
              isActive={selectedCompany?.id === company.id}
              onClick={() => setSelectedCompany(company)}
            />
          ))}
        </div>
      </div>

      {/* Main Panel */}
      <div className="flex-1 flex flex-col">
        {selectedCompany ? (
          <>
            {/* Company Header */}
            <div className="p-6 bg-white shadow-sm border-b border-gray-200">
              <h1 className="text-2xl font-bold">{selectedCompany.name || "Unknown Name"}</h1>
              <p className="text-gray-500">
                {selectedCompany.symbol || "N/A"} • {selectedCompany.sector || "N/A"}
              </p>
            </div>

            {/* Chart */}
            <div className="flex-1 p-6">
              {isLoading ? (
                <p>Loading stock data...</p>
              ) : (stockData.length === 0) ? (
                <p>No historical data available</p>
              ) : (
                <Line key={selectedCompany?.id} data={chartData} />
              )}
            </div>

            {/* AI Prediction */}
            <div className="p-6 bg-gray-50">
              <AIPrediction company={selectedCompany} isLoading={isLoading} />
            </div>
          </>
        ) : (
          <WelcomeMessage />
        )}
      </div>
    </div>
  );
};

export default StockDashboard;
